	('43266a85-830b-4a8a-b0ec-305153cb3c84', '9a13a580-7e2a-4b6a-93b3-467712adc5e3', '{"summary": "主隊法蘭西展現出壓倒性優勢，憑藉強大的實力和穩定的防守掌控賽局。客場伊拉克因缺乏數據與實戰表現而處於絕對劣勢，預測大比分勝出無懸念。", "confidence": 8, "key_factors": ["France實力遠超Iraq", "FIFA排名差距明顯", "法國隊近期保持穩定"], "radar_chart": {"away_team": [], "home_team": [], "categories": []}, "over_under_2.5": true, "source_quality": {"score": 5.0, "sources": ["official_api", "official_api", "official_api", "official_api", "official_api", "official_api", "official_api"]}, "predicted_score": [3, 1], "away_total_score": 0.0, "home_total_score": 0.0, "away_win_probability": 0.0, "home_win_probability": 1.0}', '2026-06-12 11:45:02.897333+08', '2026-06-12 11:45:02.897333+08'),
	('d7a9d467-8d90-4e17-b5dd-4b1b1ee3e1b0', '6148e4a3-41f3-4e76-bb6d-2c4a93662326', '{"summary": "由於韓國為主辦方，擁有地利之便，但兩國在 FIFA 中數據均不詳。考慮到亞洲球隊的主场表现以及捷克队近期状态不佳的综合因素做出判断，认为韩国略占优势。", "confidence": 2, "key_factors": ["主隊在家場優勢", "客隊世界排名較低"], "radar_chart": {"away_team": [4.0, 5.0, 5.0, 6.0, 5.0, 2.0], "home_team": [5.0, 6.0, 6.0, 7.0, 6.0, 3.0], "categories": ["整體戰術實力", "前場進攻", "中場掌控", "後防穩定", "門將表現", "近期狀態"]}, "actual_result": {"is_hit": true, "settled_at": "2026-06-13T11:40:26.917632", "actual_score": "2-1", "actual_winner": "home", "home_prob_norm": 0.65, "predicted_winner": "home"}, "source_quality": {"score": 5.0, "sources": ["official_api", "official_api", "official_api", "official_api", "official_api", "official_api", "official_api"]}, "predicted_score": "2-1", "away_total_score": 9.0, "home_total_score": 18.0, "away_win_probability": 0.35, "home_win_probability": 0.65}', '2026-06-11 17:52:58.190778+08', '2026-06-13 11:40:26.905339+08'),
	('5e3dde3b-e820-464e-9168-b392f24f2adc', 'd63e85e3-32de-4664-a86b-9183544e5d3d', '{"summary": "Canada vs Bosnia-Herzegovina：主隊近期0-0，場均0.0分/失0.0分；客隊近期0-0，場均0.0分/失0.0分。", "confidence": 5, "key_factors": ["主隊近期0-0", "客隊近期0-0"], "radar_chart": {"away_team": [5.0, 4.8, 4.5, 4.2, 4.0, 3.8], "home_team": [5.0, 4.8, 4.5, 4.2, 4.0, 3.8], "categories": ["整體戰術實力", "前場進攻", "中場掌控", "後防穩定", "門將表現", "近期狀態"]}, "actual_result": {"is_hit": false, "settled_at": "2026-06-13T11:40:26.917766", "actual_score": "1-1", "actual_winner": "draw", "home_prob_norm": 0.5, "predicted_winner": "home"}, "source_quality": {"score": 5.0, "sources": ["official_api", "official_api", "official_api", "official_api", "official_api", "official_api", "official_api"]}, "predicted_score": "0-0", "away_total_score": 4.4, "home_total_score": 4.4, "away_win_probability": 0.5, "home_win_probability": 0.5}', '2026-06-11 17:53:36.25258+08', '2026-06-13 11:40:26.905339+08'),
	('249142aa-1896-440c-87b8-11fa9417b6c7', '574997fc-eaa9-42a2-8eb5-fcd7b621783e', '{"summary": "雙方缺乏近期真實戰績數據，僅憑主場與客隊屬性推斷，整體分析受限於資料缺失。需考慮 FIFA 邀請賽的性質與球隊備戰狀況進行評估。", "confidence": 3, "key_factors": ["Algeria 主場優勢", "FIFA 比賽的特殊性導致數據不足"], "radar_chart": {"away_team": [], "home_team": [], "categories": []}, "source_quality": {"score": 5.0, "sources": ["official_api", "official_api", "official_api", "official_api", "official_api", "official_api", "official_api"]}, "predicted_score": "1-0", "away_total_score": 0.0, "home_total_score": 0.0, "away_win_probability": 0.48, "home_win_probability": 0.52}', '2026-06-10 08:18:54.66061+08', '2026-06-10 08:40:23.076946+08'),
	('d4a3cbcf-1c21-4fa7-b2de-6c52b9b551f7', '4280480f-3ff8-4e24-aa1d-c8580da9fea5', '{"summary": "巴西与摩洛哥均为世界杯顶级强队，但巴西底蕴深厚、攻守均衡，尤其前场攻击力突出；摩洛哥以防守反击著称，但面对巴西整体压制可能难以组织有效进攻。综合排名与历史表现，巴西胜率更高，预计比分2-1。", "confidence": 7, "key_factors": ["巴西世界排名第1，整体实力与大赛经验占优", "摩洛哥虽排名第2，但近年崛起迅速，防守坚韧", "缺乏近期交锋与状态数据，参考排名差距巴西稍占上风"], "radar_chart": {"away_team": [8.0, 7.0, 8.0, 8.0, 8.0, 7.0], "home_team": [9.0, 9.0, 8.0, 8.0, 8.0, 7.0], "categories": ["整體戰術實力", "前場進攻", "中場掌控", "後防穩定", "門將表現", "近期狀態"]}, "actual_result": {"is_hit": false, "settled_at": "2026-06-14T08:42:23.284231", "actual_score": "1-1", "settlement_type": "over_under_2.5", "actual_over_under": false, "actual_total_goals": 2.0, "predicted_over_under": true}, "over_under_2_5": true, "source_quality": {"score": 5.0, "sources": ["official_api", "official_api", "official_api", "official_api", "official_api", "official_api", "official_api"]}, "predicted_score": "2-1", "away_win_probability": 0.35, "home_win_probability": 0.65}', '2026-06-12 21:56:17.554405+08', '2026-06-14 08:42:23.269196+08'),
	('c2821e50-8c8f-4f5d-8e78-09d692c4a412', 'abe64b12-d454-43f1-8b37-5c8b18f12ae2', '{"summary": "主隊比利時在FIFA排名中位列第一，整體實力和進攻能力均顯著優於客場球隊，雖然本賽季表現起伏較大但仍具備取勝優勢。", "confidence": 5, "key_factors": ["比利時世界盃排名第1實力強勁", "伊朗缺乏近期比賽數據難以評估狀態", "主隊戰績穩定但防守漏洞明顯"], "radar_chart": {"away_team": [], "home_team": [], "categories": []}, "over_under_2_5": false, "source_quality": {"score": 5.0, "sources": ["official_api", "official_api", "official_api", "official_api", "official_api", "official_api", "official_api"]}, "predicted_score": 1.0, "away_total_score": 0.0, "home_total_score": 0.0, "away_win_probability": 0.27, "home_win_probability": 0.73}', '2026-06-12 11:45:33.607993+08', '2026-06-12 11:45:33.607993+08'),
	('62e3aaae-c5b6-4980-b484-e51b1fb61f97', '69c96ba3-94d2-4639-9810-35bfdbbec57d', '{"summary": "United States在FIFA世界盃排名第1，顯示整體實力強勁，而Paraguay排名第2，雖有競爭力但略遜一籌。由於缺乏近期比賽和對戰歷史，分析基於排名差距，主場優勢進一步增強United States的勝算。預測比分為2-1，總進球數可能超過2.5球。", "confidence": 7, "key_factors": ["United States FIFA排名第1，實力優於Paraguay", "Paraguay排名第2，但缺乏近期比賽數據", "無對戰歷史，主場優勢可能影響結果"], "radar_chart": {"away_team": [7.5, 7.0, 7.0, 7.0, 7.0, 6.5], "home_team": [8.5, 8.0, 8.0, 7.5, 7.5, 7.0], "categories": ["整體戰術實力", "前場進攻", "中場掌控", "後防穩定", "門將表現", "近期狀態"]}, "actual_result": {"is_hit": true, "settled_at": "2026-06-13T11:40:26.917446", "actual_score": "4-1", "settlement_type": "over_under_2.5", "actual_over_under": true, "actual_total_goals": 5.0, "predicted_over_under": true}, "over_under_2_5": true, "source_quality": {"score": 5.0, "sources": ["official_api", "official_api", "official_api", "official_api", "official_api", "official_api", "official_api"]}, "predicted_score": "2-1", "away_total_score": 0.0, "home_total_score": 0.0, "away_win_probability": 0.35, "home_win_probability": 0.65}', '2026-06-12 21:57:34.867201+08', '2026-06-13 11:40:26.905339+08'),
	('f6026d50-8ab6-49a5-b0c1-462af8a31ce9', '754e7c1c-9a6f-4298-a376-f19722f2f51d', '{"summary": "雖然沙特客場表現不明確，但西班牙展現了壓倒性的實力與狀態。", "confidence": 8, "key_factors": ["Spain戰績7勝0敗", "Saudi Arabia無近期比賽數據", "主隊西班牙FIFA排名第1"], "radar_chart": {"away_team": [3.0, 4.0, 3.5, 4.0, 3.5, 2.5], "home_team": [10.0, 9.0, 8.5, 9.0, 8.5, 10.0], "categories": ["整體戰術實力", "前場進攻", "中場掌控", "後防穩定", "門將表現", "近期狀態"]}, "over_under_2.5": true, "source_quality": {"score": 5.0, "sources": ["official_api", "official_api", "official_api", "official_api", "official_api", "official_api", "official_api"]}, "predicted_score": "3-0", "away_total_score": 0.0, "home_total_score": 0.0, "away_win_probability": 0.0, "home_win_probability": 1.0}', '2026-06-12 11:46:08.996025+08', '2026-06-12 11:46:08.996025+08'),
	('8fd14c00-52dc-43c3-b23a-9934a5b88802', 'fd50fd52-75c5-46ed-8df9-b5bb8be1033d', '{"summary": "基於缺乏實際比賽數據及聯盟排名信息，但考慮到雙方背景與一般足球常識進行分析。England作為FIFA成員國通常具備更高層次的戰術體系與球員水準。Panama在美洲杯等賽事中表現可觀但整體實力仍遜色一籌。", "confidence": 3, "key_factors": ["實力差距懸殊", "客隊經驗豐富", "缺少對陣數據"], "radar_chart": {"away_team": [8.2, 8.0, 7.9, 7.8, 7.6, 7.7], "home_team": [5.8, 4.9, 5.7, 6.1, 5.3, 5.5], "categories": ["整體戰術實力", "前場進攻", "中場掌控", "後防穩定", "門將表現", "近期狀態"]}, "source_quality": {"score": 5.0, "sources": ["official_api", "official_api", "official_api", "official_api", "official_api", "official_api", "official_api"]}, "predicted_score": "0-2", "away_total_score": 47.3, "home_total_score": 31.3, "away_win_probability": 0.85, "home_win_probability": 0.15}', '2026-06-10 08:19:22.953134+08', '2026-06-10 08:40:42.148506+08'),
	('135ab7ec-e5ac-401b-9b94-8ba4a9417a55', 'b8f2e66b-f474-4b64-bf29-60cde5e8b6e9', '{"summary": "Qatar排名第3略優於瑞士第4，但缺乏近期比賽數據，狀態成謎；瑞士近期5場比賽2勝2平1負，場均進球2.2，進攻端有威脅，防守場均失1.8略顯不穩。綜合考量，瑞士小佔上風，但勝負差距不大，預測比分接近。", "confidence": 6, "key_factors": ["Qatar在FIFA世界排名略高（第3名）", "Switzerland近期有實戰記錄，場均進球2.2且進攻穩定", "Qatar缺乏近期比賽數據，狀態不明朗，存在不確定性"], "radar_chart": {"away_team": [6.5, 7.0, 6.0, 6.0, 6.0, 6.0], "home_team": [7.0, 6.0, 6.0, 6.0, 7.0, 5.0], "categories": ["整體戰術實力", "前場進攻", "中場掌控", "後防穩定", "門將表現", "近期狀態"]}, "actual_result": {"is_hit": false, "settled_at": "2026-06-14T08:42:23.284078", "actual_score": "1-1", "settlement_type": "over_under_2.5", "actual_over_under": false, "actual_total_goals": 2.0, "predicted_over_under": true}, "over_under_2_5": true, "source_quality": {"score": 5.0, "sources": ["official_api", "official_api", "official_api", "official_api", "official_api", "official_api", "official_api"]}, "predicted_score": "1-2", "away_win_probability": 0.55, "home_win_probability": 0.45}', '2026-06-12 21:59:15.842781+08', '2026-06-14 08:42:23.269196+08'),
