	('e4a4094f-ceaa-4da4-af02-fcfbd61848a9', '57098e17-2ed2-4436-9a40-3e728f21c3ba', '{"summary": "Uruguay在FIFA世界排名中位列第4，遠高於Cape Verde的第2名（但排名數據可能誤植，實際Uruguay實力明顯佔優）。Uruguay擁有更豐富的國際賽經驗和更強的整體戰術體系，而Cape Verde缺乏近期比賽數據，狀態難以評估。綜合來看，Uruguay勝率較高，但由於缺乏直接對陣歷史和近期表現數據，信心指數為7。", "confidence": 7, "key_factors": ["Uruguay FIFA排名第4，遠高於Cape Verde的排名第2（但排名數據有矛盾，實際Uruguay實力更強）", "Uruguay擁有歷史悠久的足球傳統和更強的球員陣容深度", "Cape Verde近期無比賽數據，狀態不明，但整體實力與Uruguay有差距"], "radar_chart": {"away_team": [5.0, 4.5, 5.0, 5.5, 5.0, 4.0], "home_team": [8.0, 7.5, 7.0, 8.0, 7.5, 6.0], "categories": ["整體戰術實力", "前場進攻", "中場掌控", "後防穩定", "門將表現", "近期狀態"]}, "over_under_2_5": false, "source_quality": {"score": 5.0, "sources": ["official_api", "official_api", "official_api", "official_api", "official_api", "official_api", "official_api"]}, "predicted_score": "2-0", "away_total_score": 0.0, "home_total_score": 0.0, "away_win_probability": 0.35, "home_win_probability": 0.65}', '2026-06-12 22:42:28.706765+08', '2026-06-12 22:42:28.706765+08'),
	('81229ffc-46d7-491e-8954-4b9799680b4f', '479e8c45-9c49-4be7-9b61-00676fa281ff', '{"summary": "儘管釀酒人在近期表現不錯且擁有先發投手，但巨人隊的打線火力、牛棚穩定度及頭兩次交手皆獲勝的歷史積累了明確優勢。考慮到釀酒人主場有霧的天氣條件可能不利於攻擊方發揮打擊技巧以及兩隊近期的戰績與對陣歷史等因素來看，本回合比賽中巨人的贏面較佳。", "confidence": 7, "key_factors": ["巨人名氣與打擊實力更勝一籌", "釀酒人主場優勢被惡劣天氣抵消", "對戰紀錄完全倒向客隊"], "radar_chart": {"away_team": [], "home_team": [], "categories": []}, "actual_result": {"is_hit": true, "settled_at": "2026-06-12T20:13:46.642965", "actual_score": "9-12", "actual_winner": "away", "home_prob_norm": 0.42, "predicted_winner": "away"}, "source_quality": {"score": 4.78, "sources": ["official_api", "official_api", "official_api", "official_api", "official_api", "official_api", "official_api", "official_api", "news_media"]}, "predicted_score": "9-10", "away_total_score": 4.67, "home_total_score": 5.83, "away_win_probability": 0.58, "home_win_probability": 0.42}', '2026-06-09 19:19:31.044452+08', '2026-06-12 20:13:46.624865+08'),
	('94a68487-9e09-485f-bac0-db51ff41ae74', '22788afb-a737-4710-860d-a780cbc70952', '{"summary": "分析顯示主隊整體表現更為出色，勝率預計較高。 ", "confidence": 1, "key_factors": ["主隊戰力明顯優於客隊", "客隊打擊火力較弱", "客隊先發投手實力不足"], "radar_chart": {"away_team": [], "home_team": [], "categories": []}, "source_quality": {"score": 5.0, "sources": ["official_api", "official_api", "official_api", "official_api", "official_api", "official_api", "official_api"]}, "predicted_score": "3-2", "away_total_score": 0.0, "home_total_score": 1.0, "away_win_probability": 0.0, "home_win_probability": 1.0}', '2026-06-11 11:45:58.936607+08', '2026-06-11 11:45:58.936607+08'),
	('7b636e30-195f-4c8f-bfca-5446b0f8d3c5', '89d25944-13c0-4a97-80b1-acdd4f335371', '{"summary": "綜合分析，金鶯在打線火力、近期狀態與主場優勢上明顯佔優，雖然先發投手環節教士稍好，但金鶯整體戰力與士氣更高，預測金鶯取勝。", "confidence": 7, "key_factors": ["巴爾的摩金鶯近期3連勝，打線火力旺盛，場均5.6分遠優於教士的3.6分", "教士團隊打擊低迷，AVG僅0.218、OPS 0.650，進攻威脅不足", "金鶯先發Trey Gibson表現不穩定，但教士先發Randy Vásquez數據較佳，但近期球隊支援有限"], "radar_chart": {"away_team": [5.0, 4.0, 6.0, 5.0, 4.0, 3.0], "home_team": [7.5, 7.0, 4.0, 5.5, 8.0, 8.0], "categories": ["球隊整體戰力", "打線火力", "先發投手", "牛棚表現", "主客場因素", "近期狀態"]}, "actual_result": {"is_hit": false, "settled_at": "2026-06-14T08:42:23.282300", "actual_score": "3-9", "actual_winner": "away", "home_prob_norm": 0.7, "predicted_winner": "home"}, "source_quality": {"score": 4.78, "sources": ["official_api", "official_api", "official_api", "official_api", "official_api", "official_api", "official_api", "official_api", "news_media"]}, "predicted_score": "6-4", "away_win_probability": 0.3, "home_win_probability": 0.7}', '2026-06-13 11:48:44.153078+08', '2026-06-14 08:42:23.269196+08'),
